let messages = [];

document.querySelectorAll('.font-user-message, .font-claude-message').forEach(block => {
  let role = block.classList.contains('font-user-message') ? 'Utilisateur' : 'Claude';
  let text = Array.from(block.querySelectorAll('p'))
    .map(p => p.textContent.trim())
    .filter(Boolean)
    .join('\n');

  messages.push({ role, text });
});

console.log(messages);

