# SuperLoader.py

import importlib
import os
import json
import sys

class SuperLoader:

    @staticmethod
    def call(object_type, name, *args, **kwargs):
        entry = SuperLoader.get_entry(object_type, name)
        if not entry:
            raise ValueError(f"❌ Entrée '{name}' non trouvée dans le catalogue {object_type}.")

        path = entry["path"]
        module_name = path
        attr_name = path.split(".")[-1]

        try:
            module = importlib.import_module(module_name)
        except ImportError as e:
            # tentative d'import alternatif
            parent_module_name = ".".join(module_name.split(".")[:-1])
            module = importlib.import_module(parent_module_name)
            if not hasattr(module, attr_name):
                raise ValueError(f"❌ Impossible de charger l'objet '{name}' depuis '{entry['path']}'") from e

        target = getattr(module, attr_name)
        if callable(target):
            return target(*args, **kwargs)
        return target

    @staticmethod
    def get_entry(object_type, name):
        catalog = SuperLoader.load_catalog_direct(object_type)
        for entry in catalog:
            if entry.get("name") == name:
                return entry
        return None

    @staticmethod
    def load_catalog_direct(object_type):
        base_dir = os.getcwd()
        catalog_path = os.path.join(base_dir, "objects/core/method/resources/json", f"{object_type}_catalog.json")

        try:
            with open(catalog_path, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception as e:
            print(f"❌ Erreur chargement catalogue: {e}")
            return []

